import psycopg2
from psycopg2.extras import RealDictCursor
from typing import Optional, List, Dict, Any


def get_db_connection():
    """Create and return a database connection."""
    return psycopg2.connect(
        host="localhost",
        database="your_database",
        user="your_user",
        password="your_password"
    )


def search_users(
    username: Optional[str] = None,
    email: Optional[str] = None,
    role: Optional[str] = None,
    status: Optional[str] = None
) -> List[Dict[str, Any]]:
    """
    Search for users based on multiple filter criteria.
    
    Args:
        username: Filter by username (partial match)
        email: Filter by email (partial match)
        role: Filter by role (exact match: admin/user/guest)
        status: Filter by account status (exact match: active/suspended)
    
    Returns:
        List of user profile dictionaries
    """
    conn = get_db_connection()
    cursor = conn.cursor(cursor_factory=RealDictCursor)
    
    query = "SELECT * FROM users WHERE 1=1"
    params = []
    
    if username is not None:
        query += " AND username ILIKE %s"
        params.append(f"%{username}%")
    
    if email is not None:
        query += " AND email ILIKE %s"
        params.append(f"%{email}%")
    
    if role is not None:
        query += " AND role = %s"
        params.append(role)
    
    if status is not None:
        query += " AND status = %s"
        params.append(status)
    
    cursor.execute(query, params)
    results = cursor.fetchall()
    
    cursor.close()
    conn.close()
    
    return [dict(row) for row in results]


def get_user_by_id(user_id: int) -> Optional[Dict[str, Any]]:
    """Fetch a single user by ID."""
    conn = get_db_connection()
    cursor = conn.cursor(cursor_factory=RealDictCursor)
    
    cursor.execute("SELECT * FROM users WHERE id = %s", (user_id,))
    result = cursor.fetchone()
    
    cursor.close()
    conn.close()
    
    return dict(result) if result else None


def get_all_users() -> List[Dict[str, Any]]:
    """Fetch all users."""
    conn = get_db_connection()
    cursor = conn.cursor(cursor_factory=RealDictCursor)
    
    cursor.execute("SELECT * FROM users")
    results = cursor.fetchall()
    
    cursor.close()
    conn.close()
    
    return [dict(row) for row in results]


